`timescale 1ns/1ps

// node_conv_288 -- dram-backed-weights pointwise (1x1) conv2d, stride=2.
// IC=1024, OC=2048, IH=IW=14, OH=OW=7, MP=4, channel_tile=32.
// Weights live in DRAM and are streamed through a 64-bit AXI read channel
// into two 4096-byte on-chip pass caches (cache_a / cache_b). Bias is
// the only constant ROM loaded via $readmemh.
//
// Latency contract (authoritative from LayerIR):
//   first valid_out fires 1 + OC_PASSES*(MP*K_TOTAL+6) = 2100225 cycles
//   after the first accepted valid_in of each vector.
//
// Multi-vector tail rule:
//   Stride=2 with IH=14 -> only 49 of 196 input grid positions produce
//   outputs. After the last active output pixel of vector N is emitted,
//   the FSM MUST jump straight to vector N+1's startup; iterating the
//   15 trailing inactive input pixels would keep ready_in high while
//   the TB has already advanced to vector N+1, contaminating vector
//   N+1's pixel (0,0) with offset data and overshooting per-vector
//   latency by ~8310 cycles. Tracked by active_pixel_counter.

module node_conv_288 (
    input  wire             clk,
    input  wire             rst_n,
    input  wire             valid_in,
    output reg              ready_in,
    input  wire [255:0]     data_in,
    output reg              valid_out,
    output reg  [255:0]     data_out,
    output reg              weights_arvalid,
    input  wire             weights_arready,
    output reg  [31:0]      weights_araddr,
    output reg  [7:0]       weights_arlen,
    input  wire             weights_rvalid,
    output reg              weights_rready,
    input  wire [63:0]      weights_rdata,
    input  wire             weights_rlast
);

    // ----------------------------------------------------------------
    // Geometry
    // ----------------------------------------------------------------
    localparam IC              = 1024;
    localparam OC              = 2048;
    localparam K_TOTAL         = 1024;
    localparam IH              = 14;
    localparam IW              = 14;
    localparam OH              = 7;
    localparam OW              = 7;
    localparam ACTIVE_PIXELS   = OH*OW;             // 49
    localparam SH              = 2;
    localparam SW              = 2;
    localparam MP              = 4;
    localparam OC_PASSES       = OC/MP;             // 512
    localparam CHANNEL_TILE    = 32;
    localparam IN_BEATS        = IC/CHANNEL_TILE;   // 32
    localparam OUT_BEATS       = OC/CHANNEL_TILE;   // 64
    localparam BEAT_BITS       = 256;
    localparam BYTES_PER_PASS  = MP*K_TOTAL;        // 4096
    localparam BEATS_PER_PASS  = BYTES_PER_PASS/8;  // 512
    localparam TOTAL_IN_PIXELS = IH*IW;             // 196

    // ----------------------------------------------------------------
    // Quantization scale (sign-aware rounding)
    // ----------------------------------------------------------------
    localparam SCALE_MULT  = 15825;
    localparam SCALE_SHIFT = 20;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + $clog2(K_TOTAL);   // 26
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;   // 33
    localparam integer SCALE_MAG_W   = $clog2(SCALE_MULT + 1);                    // 14
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;                           // 15
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;                  // 48
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    // [INVARIANT:ROUNDING] Pre-compute the negative-branch bias as an
    // explicit signed localparam so the surrounding ternary stays signed
    // and `>>>` performs an arithmetic shift on negative scaled values.
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 = SCALE_ROUND_HALF - 1;

    // ----------------------------------------------------------------
    // Bias ROM (INT32 per LayerIR contract; one 32-bit value per OC channel).
    // ----------------------------------------------------------------
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] bias_rom [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_288_bias.hex", bias_rom);
    end

    // ----------------------------------------------------------------
    // Pass weight caches (double-buffered)
    // ----------------------------------------------------------------
    (* ram_style = "block" *)
    reg [63:0] cache_a [0:BEATS_PER_PASS-1];
    (* ram_style = "block" *)
    reg [63:0] cache_b [0:BEATS_PER_PASS-1];

    reg cache_a_loaded;
    reg cache_b_loaded;

    // ----------------------------------------------------------------
    // Input latch (full IC channels)
    // ----------------------------------------------------------------
    reg signed [7:0] in_latch [0:IC-1];

    // ----------------------------------------------------------------
    // Output buffer (one full output pixel = OC INT8)
    // ----------------------------------------------------------------
    reg [OC*8-1:0] out_buffer;

    // ----------------------------------------------------------------
    // Per-lane accumulators / scaled holders
    // ----------------------------------------------------------------
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;

    // ----------------------------------------------------------------
    // AR / weight prefetch FSM
    // ----------------------------------------------------------------
    localparam AR_IDLE      = 3'd0;
    localparam AR_ISSUE     = 3'd1;
    localparam AR_WAIT_DATA = 3'd2;
    localparam AR_DONE      = 3'd3;

    reg [2:0] ar_state;
    reg [9:0] ar_beat_counter;
    reg       ar_burst_index;
    reg [9:0] ar_pass_target;
    reg       ar_target_cache;
    reg       ar_kick_pending;

    reg        cache_we;
    reg        cache_we_target;
    reg [9:0]  cache_we_addr;
    reg [63:0] cache_we_data;

    reg ar_kick;
    reg ar_restart;

    always @(posedge clk) begin
        if (cache_we) begin
            if (cache_we_target == 1'b0)
                cache_a[cache_we_addr] <= cache_we_data;
            else
                cache_b[cache_we_addr] <= cache_we_data;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ar_state         <= AR_IDLE;
            ar_beat_counter  <= 10'd0;
            ar_burst_index   <= 1'b0;
            ar_pass_target   <= 10'd0;
            ar_target_cache  <= 1'b0;
            weights_arvalid  <= 1'b0;
            weights_araddr   <= 32'd0;
            weights_arlen    <= 8'd0;
            weights_rready   <= 1'b0;
            cache_we         <= 1'b0;
            cache_we_target  <= 1'b0;
            cache_we_addr    <= 10'd0;
            cache_we_data    <= 64'd0;
            ar_kick_pending  <= 1'b0;
            cache_a_loaded   <= 1'b0;
            cache_b_loaded   <= 1'b0;
        end else if (ar_restart) begin
            ar_state         <= AR_IDLE;
            ar_beat_counter  <= 10'd0;
            ar_burst_index   <= 1'b0;
            ar_pass_target   <= 10'd0;
            ar_target_cache  <= 1'b0;
            weights_arvalid  <= 1'b0;
            weights_rready   <= 1'b0;
            cache_we         <= 1'b0;
            ar_kick_pending  <= 1'b0;
            cache_a_loaded   <= 1'b0;
            cache_b_loaded   <= 1'b0;
        end else begin
            cache_we <= 1'b0;

            if (ar_kick) ar_kick_pending <= 1'b1;

            case (ar_state)
                AR_IDLE: begin
                    weights_arvalid <= 1'b0;
                    weights_rready  <= 1'b0;
                    if (ar_kick_pending && ar_pass_target < OC_PASSES) begin
                        ar_burst_index  <= 1'b0;
                        ar_beat_counter <= 10'd0;
                        ar_state        <= AR_ISSUE;
                        ar_kick_pending <= 1'b0;
                        if (ar_target_cache == 1'b0)
                            cache_a_loaded <= 1'b0;
                        else
                            cache_b_loaded <= 1'b0;
                    end
                end
                AR_ISSUE: begin
                    weights_arvalid <= 1'b1;
                    weights_arlen   <= 8'd255;
                    weights_araddr  <= (ar_pass_target * BYTES_PER_PASS) +
                                       (ar_burst_index ? 32'd2048 : 32'd0);
                    if (weights_arready && weights_arvalid) begin
                        weights_arvalid <= 1'b0;
                        weights_rready  <= 1'b1;
                        ar_state        <= AR_WAIT_DATA;
                    end
                end
                AR_WAIT_DATA: begin
                    weights_rready <= 1'b1;
                    if (weights_rvalid) begin
                        cache_we        <= 1'b1;
                        cache_we_target <= ar_target_cache;
                        cache_we_addr   <= (ar_burst_index ? 10'd256 : 10'd0) + ar_beat_counter;
                        cache_we_data   <= weights_rdata;
                        ar_beat_counter <= ar_beat_counter + 10'd1;
                        if (weights_rlast) begin
                            weights_rready  <= 1'b0;
                            ar_beat_counter <= 10'd0;
                            if (ar_burst_index == 1'b0) begin
                                ar_burst_index <= 1'b1;
                                ar_state       <= AR_ISSUE;
                            end else begin
                                ar_state <= AR_DONE;
                            end
                        end
                    end
                end
                AR_DONE: begin
                    if (ar_target_cache == 1'b0)
                        cache_a_loaded <= 1'b1;
                    else
                        cache_b_loaded <= 1'b1;
                    ar_pass_target  <= ar_pass_target + 10'd1;
                    ar_target_cache <= ~ar_target_cache;
                    ar_state        <= AR_IDLE;
                end
                default: ar_state <= AR_IDLE;
            endcase
        end
    end

    // ----------------------------------------------------------------
    // Compute FSM
    // ----------------------------------------------------------------
    localparam ST_INIT_BOOT  = 4'd0;
    localparam ST_BOOT_WAIT  = 4'd1;
    localparam ST_INPUT      = 4'd2;
    localparam ST_RUNNING    = 4'd3;
    localparam ST_BIAS_SCALE = 4'd4;
    localparam ST_PACK       = 4'd5;
    localparam ST_STREAM_OUT = 4'd6;
    localparam ST_DISCARD    = 4'd7;
    localparam ST_NEXT       = 4'd8;

    reg [3:0] state;

    reg [9:0] k_counter;
    reg [1:0] lane_counter;
    reg [9:0] oc_pass;
    reg [5:0] in_beat_index;
    reg [6:0] out_beat;
    reg       active_cache_sel;

    reg [4:0] in_row;
    reg [4:0] in_col;
    reg [7:0] in_pixel_counter;
    // Counts how many active output pixels this vector has emitted.
    // When it reaches ACTIVE_PIXELS the FSM skips the trailing inactive
    // input pixels and starts vector N+1 immediately.
    reg [6:0] active_pixel_counter;
    wire pix_active = (in_row[0] == 1'b0) && (in_col[0] == 1'b0);

    wire active_cache_loaded = active_cache_sel ? cache_b_loaded : cache_a_loaded;

    reg                     mac_valid_q1;
    reg [1:0]               mac_lane_q1;
    reg [9:0]               mac_k_q1;
    reg [10:0]              mac_global_oc_q1;
    reg                     mac_done_issuing;

    reg                     mac_valid_q2;
    reg [1:0]               mac_lane_q2;
    reg [9:0]               mac_k_q2;
    reg [10:0]              mac_global_oc_q2;

    reg                     mac_valid_q3;
    reg [1:0]               mac_lane_q3;
    reg [10:0]              mac_global_oc_q3;

    reg [11:0] weight_addr_q;
    reg [63:0] cache_word_q;
    reg [2:0]  byte_in_word_q;

    wire signed [7:0] weight_q = $signed(cache_word_q[byte_in_word_q*8 +: 8]);

    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;

    wire [10:0] current_global_oc = oc_pass * MP + lane_counter;
    wire [11:0] cache_byte_addr   = lane_counter * K_TOTAL + k_counter;

    integer i;
    integer lane;
    integer ch;
    integer bias_oc;
    integer out_oc;

    always @(posedge clk) begin
        weight_addr_q  <= cache_byte_addr;
        cache_word_q   <= active_cache_sel ? cache_b[weight_addr_q[11:3]]
                                           : cache_a[weight_addr_q[11:3]];
        byte_in_word_q <= weight_addr_q[2:0];
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state                <= ST_INIT_BOOT;
            ready_in             <= 1'b0;
            valid_out            <= 1'b0;
            data_out             <= {BEAT_BITS{1'b0}};
            in_beat_index        <= 6'd0;
            in_row               <= 5'd0;
            in_col               <= 5'd0;
            in_pixel_counter     <= 8'd0;
            active_pixel_counter <= 7'd0;
            k_counter            <= 10'd0;
            lane_counter         <= 2'd0;
            oc_pass              <= 10'd0;
            out_beat             <= 7'd0;
            out_buffer           <= {(OC*8){1'b0}};
            active_cache_sel     <= 1'b0;
            mac_valid_q1         <= 1'b0;
            mac_lane_q1          <= 2'd0;
            mac_k_q1             <= 10'd0;
            mac_global_oc_q1     <= 11'd0;
            mac_done_issuing     <= 1'b0;
            mac_valid_q2         <= 1'b0;
            mac_lane_q2          <= 2'd0;
            mac_k_q2             <= 10'd0;
            mac_global_oc_q2     <= 11'd0;
            mac_valid_q3         <= 1'b0;
            mac_lane_q3          <= 2'd0;
            mac_global_oc_q3     <= 11'd0;
            mul_q                <= {PROD_W{1'b0}};
            ar_kick              <= 1'b0;
            ar_restart           <= 1'b0;
            v_tmp                <= {SCALED_W{1'b0}};
            for (i = 0; i < IC; i = i + 1)
                in_latch[i] <= 8'sd0;
            for (lane = 0; lane < MP; lane = lane + 1) begin
                acc   [lane] <= {ACC_W{1'b0}};
                scaled[lane] <= {SCALED_W{1'b0}};
            end
        end else begin
            ar_kick    <= 1'b0;
            ar_restart <= 1'b0;
            valid_out  <= 1'b0;

            mac_valid_q2     <= mac_valid_q1;
            mac_lane_q2      <= mac_lane_q1;
            mac_k_q2         <= mac_k_q1;
            mac_global_oc_q2 <= mac_global_oc_q1;

            mul_q            <= weight_q * $signed(in_latch[mac_k_q2]);
            mac_valid_q3     <= mac_valid_q2;
            mac_lane_q3      <= mac_lane_q2;
            mac_global_oc_q3 <= mac_global_oc_q2;

            if (mac_valid_q3 && mac_global_oc_q3 < OC) begin
                acc[mac_lane_q3] <= acc[mac_lane_q3] + $signed(mul_q);
            end

            case (state)

            ST_INIT_BOOT: begin
                // [INVARIANT:READY_IN_GATING] hold ready_in low until
                // pass-0 weights are prefetched into cache_a.
                ready_in <= 1'b0;
                ar_kick  <= 1'b1;
                state    <= ST_BOOT_WAIT;
            end

            ST_BOOT_WAIT: begin
                ready_in <= 1'b0;
                if (active_cache_loaded) begin
                    ready_in      <= 1'b1;
                    in_beat_index <= 6'd0;
                    state         <= ST_INPUT;
                end
            end

            ST_INPUT: begin
                mac_valid_q1 <= 1'b0;
                if (valid_in && ready_in) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                        in_latch[ch] <= $signed(data_in[ch*8 +: 8]);
                    in_beat_index <= 6'd1;

                    if (pix_active) begin
                        k_counter        <= 10'd0;
                        lane_counter     <= 2'd0;
                        oc_pass          <= 10'd0;
                        mac_done_issuing <= 1'b0;
                        active_cache_sel <= 1'b0;
                        for (lane = 0; lane < MP; lane = lane + 1)
                            acc[lane] <= {ACC_W{1'b0}};
                        ar_kick <= 1'b1;
                        state   <= ST_RUNNING;
                    end else begin
                        state <= ST_DISCARD;
                    end
                end
            end

            ST_RUNNING: begin
                if (in_beat_index < IN_BEATS && valid_in && ready_in) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                        in_latch[in_beat_index * CHANNEL_TILE + ch]
                            <= $signed(data_in[ch*8 +: 8]);
                    if (in_beat_index == IN_BEATS-1) begin
                        ready_in      <= 1'b0;
                        in_beat_index <= 6'd0;
                    end else begin
                        in_beat_index <= in_beat_index + 6'd1;
                    end
                end

                if (mac_done_issuing) begin
                    mac_valid_q1 <= 1'b0;
                    if (!mac_valid_q1 && !mac_valid_q2 && !mac_valid_q3) begin
                        mac_done_issuing <= 1'b0;
                        state            <= ST_BIAS_SCALE;
                    end
                end else if (active_cache_loaded) begin
                    mac_valid_q1     <= 1'b1;
                    mac_lane_q1      <= lane_counter;
                    mac_k_q1         <= k_counter;
                    mac_global_oc_q1 <= current_global_oc;
                    if (lane_counter == MP-1) begin
                        lane_counter <= 2'd0;
                        if (k_counter == K_TOTAL-1) begin
                            mac_done_issuing <= 1'b1;
                        end else begin
                            k_counter <= k_counter + 10'd1;
                        end
                    end else begin
                        lane_counter <= lane_counter + 2'd1;
                    end
                end else begin
                    mac_valid_q1 <= 1'b0;
                end
            end

            ST_BIAS_SCALE: begin
                for (lane = 0; lane < MP; lane = lane + 1) begin
                    bias_oc = oc_pass * MP + lane;
                    if (bias_oc < OC)
                        scaled[lane] <= ($signed(acc[lane]) +
                                         $signed(bias_rom[bias_oc])) *
                                        $signed(SCALE_MULT_CONST);
                    else
                        scaled[lane] <= {SCALED_W{1'b0}};
                end
                state <= ST_PACK;
            end

            ST_PACK: begin
                for (lane = 0; lane < MP; lane = lane + 1) begin
                    out_oc = oc_pass * MP + lane;
                    // [INVARIANT:ROUNDING] sign-aware round; for negatives
                    // the bias is (HALF-1), NOT -HALF, because Verilog `>>>`
                    // floors toward -inf. Both branches reference SIGNED
                    // localparams so the surrounding arithmetic stays signed
                    // and `>>>` performs an arithmetic shift.
                    v_tmp = (scaled[lane] +
                             (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1
                                                       : SCALE_ROUND_HALF)
                            ) >>> SCALE_SHIFT;
                    if (out_oc < OC)
                        out_buffer[out_oc*8 +: 8] <= (v_tmp >  127) ?  8'sd127 :
                                                     (v_tmp < -128) ? -8'sd128 :
                                                                       v_tmp[7:0];
                end
                if (oc_pass == OC_PASSES - 1) begin
                    // [INVARIANT:VALID_OUT_LATENCY] first valid_out fires
                    // here, exactly 1 + OC_PASSES*(MP*K_TOTAL+6) cycles
                    // after the first accepted valid_in.
                    valid_out            <= 1'b1;
                    data_out             <= out_buffer[BEAT_BITS-1:0];
                    out_beat             <= 7'd0;
                    oc_pass              <= 10'd0;
                    active_pixel_counter <= active_pixel_counter + 7'd1;
                    state                <= ST_STREAM_OUT;
                end else begin
                    oc_pass          <= oc_pass + 10'd1;
                    active_cache_sel <= ~active_cache_sel;
                    k_counter        <= 10'd0;
                    lane_counter     <= 2'd0;
                    for (lane = 0; lane < MP; lane = lane + 1)
                        acc[lane] <= {ACC_W{1'b0}};
                    if (oc_pass + 10'd2 < OC_PASSES)
                        ar_kick <= 1'b1;
                    state <= ST_RUNNING;
                end
            end

            ST_STREAM_OUT: begin
                if (out_beat == OUT_BEATS - 1) begin
                    valid_out <= 1'b0;
                    out_beat  <= 7'd0;
                    state     <= ST_NEXT;
                end else begin
                    valid_out <= 1'b1;
                    data_out  <= out_buffer[(out_beat + 1) * BEAT_BITS +: BEAT_BITS];
                    out_beat  <= out_beat + 7'd1;
                end
            end

            ST_DISCARD: begin
                if (valid_in && ready_in) begin
                    if (in_beat_index == IN_BEATS-1) begin
                        ready_in      <= 1'b0;
                        in_beat_index <= 6'd0;
                        state         <= ST_NEXT;
                    end else begin
                        in_beat_index <= in_beat_index + 6'd1;
                    end
                end
            end

            ST_NEXT: begin
                ar_restart       <= 1'b1;
                active_cache_sel <= 1'b0;
                in_beat_index    <= 6'd0;

                if (active_pixel_counter == ACTIVE_PIXELS) begin
                    // Last active output pixel of this vector is done.
                    // Skip the trailing inactive input pixels — keeping
                    // ready_in high through them would consume vector
                    // N+1's leading beats into vector N's tail and
                    // shift every subsequent vector's pixel-0 input
                    // window. Restart fresh for vector N+1.
                    in_pixel_counter     <= 8'd0;
                    in_row               <= 5'd0;
                    in_col               <= 5'd0;
                    active_pixel_counter <= 7'd0;
                end else if (in_pixel_counter + 8'd1 == TOTAL_IN_PIXELS) begin
                    in_pixel_counter     <= 8'd0;
                    in_row               <= 5'd0;
                    in_col               <= 5'd0;
                    active_pixel_counter <= 7'd0;
                end else begin
                    in_pixel_counter <= in_pixel_counter + 8'd1;
                    if (in_col == IW - 1) begin
                        in_col <= 5'd0;
                        in_row <= in_row + 5'd1;
                    end else begin
                        in_col <= in_col + 5'd1;
                    end
                end
                state <= ST_INIT_BOOT;
            end

            default: state <= ST_INIT_BOOT;
            endcase
        end
    end

endmodule
